const fed = $('Get Federation').first().json;
const body = ($('Webhook').first().json.body) || {};
let items = [];
if (body.url) {
  items = [{ url: String(body.url), region: '' }];
} else {
  const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
  items = dirs
    .filter(d => d && d.extraction_method === 'pdf' && /^https?:\/\//.test(d.url || ''))
    .map(d => ({ url: d.url, region: d.region || '' }));
}
if (!items.length) return [{ json: { __skip: true, note: 'no pdf directory' } }];
return items.map(it => ({ json: it }));

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const fed = $('Get Federation').first().json; const fedId = fed.id;
const setFed = (body) => this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/federations/records/'+fedId, headers:pbH, body, json:true });

const picks = $('pick pdfs').all().map(i => i.json);
if (picks.length === 1 && picks[0].__skip) { await setFed({ status:'needs_review', notes:picks[0].note }); return [{ json:{ ok:false, note:picks[0].note } }]; }
const chunks = $('chunk').all().map(i => i.json);
const agents = $('Extract clubs').all().map(i => i.json);

const fivb = String(fed.fivb_code||'').toUpperCase(); const country = fed.country||'';
const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
const uslug = (s) => String(s||'').toLowerCase().normalize('NFKC').replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'').slice(0,60);
const nkey  = (s) => String(s||'').toLowerCase().normalize('NFKD').replace(/\*+/g,'').replace(/\([^)]*\)/g,' ').replace(/[^\p{L}\p{N}]+/gu,'');
const normUrl = (u) => { u=String(u||'').trim().replace(/^https?:\/\//i,''); if(!u) return ''; if(/[\s,]/.test(u)||!u.includes('.')) return ''; return 'https://'+u; };
const hostOf = (u) => String(u||'').replace(/^https?:\/\//i,'').replace(/^www\./i,'').split('/')[0].toLowerCase();
const isEmail = (e) => /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e);
const now = new Date().toISOString();
const findClub = async (k) => { const r = await this.helpers.httpRequest({ method:'GET', url:PB_URL+'/api/collections/clubs/records', qs:{ filter:"(dedup_key='"+k+"')", perPage:1 }, headers:pbH, json:true }); return (r.items&&r.items[0])||null; };
const findContact = async (e) => { const r = await this.helpers.httpRequest({ method:'GET', url:PB_URL+'/api/collections/contacts/records', qs:{ filter:"(email='"+e.replace(/'/g,'')+"')", perPage:1 }, headers:pbH, json:true }); return (r.items&&r.items[0])||null; };

const parseClubs = (raw0) => {
  let raw = String(raw0||'').trim().replace(/^```(json)?/i,'').replace(/```\s*$/,'').trim();
  try { const p=JSON.parse(raw); if (p && Array.isArray(p.clubs)) return { clubs:p.clubs, parsed:true }; } catch(e){}
  const objs=[]; const st=[];
  for (let i=0;i<raw.length;i++){ const ch=raw[i]; if(ch==='{') st.push(i); else if(ch==='}'){ const s=st.pop(); if(s!=null){ try{ const o=JSON.parse(raw.slice(s,i+1)); if(o&&typeof o==='object'&&!Array.isArray(o)&&('name' in o)) objs.push(o); }catch(_){} } } }
  return { clubs:objs, parsed: objs.length>0 };
};

const byDir = {};
for (let i=0;i<chunks.length;i++){
  const ck = chunks[i]||{}; const ag = agents[i]||{}; const d = ck.dirIndex;
  if (d==null) continue;
  if (!byDir[d]) byDir[d] = { url:ck.dirUrl||'', region:ck.region||'', md:'', clubs:[], hadContent:false, parseFail:false };
  const g = byDir[d];
  if (ck.chunk && ck.chunk.trim()){ g.hadContent = true; g.md += ck.chunk + '\n'; }
  if (!ck.scrapeFailed){ const pr = parseClubs(ag.output); if (!pr.parsed && ck.chunk && ck.chunk.trim()) g.parseFail = true; for (const x of pr.clubs) g.clubs.push(x); }
}

let created=0, updated=0, failed=0, totalClubs=0, scrapeFails=0, contactsCreated=0; const errors=[]; const perDir=[]; let detectedCount=0; const countRows=(md)=>{const ls=String(md||'').split('\n').map(l=>l.trim());const pp=ls.filter(l=>/^\|.*\|/.test(l)&&!/^\|[\s:|-]+\|$/.test(l));if(pp.length>=3)return Math.max(0,pp.length-1);return ls.filter(l=>/^([-*•]|\d+[.)])\s+\S/.test(l)).length;};
for (const d of Object.keys(byDir)){
  const g = byDir[d]; const srcUrl = g.url;
  if (!g.hadContent){ scrapeFails++; errors.push({ url:srcUrl, message:'no content (scrape/parse failed)' }); perDir.push({ url:srcUrl, clubs:0, created:0, updated:0 }); continue; } detectedCount += countRows(g.md);
  const baseOrigin = (function(){ const m=String(srcUrl).match(/^(https?:\/\/[^/]+)/i); return m?m[1]:''; })();
  const dirHost = hostOf(baseOrigin);
  const absol = (u) => { u=String(u||'').trim(); if(!u) return ''; if(/^https?:\/\//i.test(u)) return u; if(u.startsWith('//')) return 'https:'+u; if(u.startsWith('/')) return baseOrigin?baseOrigin+u:''; return baseOrigin?baseOrigin+'/'+u.replace(/^\.?\//,''):''; };
  const linkMap = {}; const re=/\[([^\]]*)\]\(([^)\s]+)\)/g; let mm;
  while((mm=re.exec(g.md))){ const a=nkey(mm[1]); let href=mm[2]; if(!a||!href||href.indexOf('#')>=0) continue; const abs=absol(href); if(!abs||hostOf(abs)!==dirHost) continue; if(!linkMap[a]) linkMap[a]=abs; }
  const entry = dirs.find(x => x && x.url === srcUrl) || {}; const dirRegion = entry.region || g.region || '';
  const seen = {}; let dc=0, du=0;
  for (const c of g.clubs){
    const name = String((c&&c.name)||'').replace(/\*+/g,'').trim(); if(!name) continue;
    const city = String((c&&c.city)||'').trim(); const region = String((c&&c.region)||'').trim() || dirRegion;
    const dedup = fivb+':'+uslug(name);   // name-only: city is LLM-variable (country-as-city etc.) and broke re-run idempotency
    if (seen[dedup]) continue; seen[dedup]=1; totalClubs++;
    let website = normUrl(c&&c.website); if (website && dirHost && hostOf(website)===dirHost) website='';
    let detail = absol(String((c&&c.detail_url)||'').trim()); if (detail && hostOf(detail)!==dirHost) detail='';
    if (!detail){ const hit = linkMap[nkey(name)]; if(hit) detail=hit; }
    const base = { federation:fedId, name, country, region, city, dedup_key:dedup, last_scraped:now };
    const full = Object.assign({}, base, { website_url:website, website_source: website?'official_list':'none', detail_url:detail, source_url:srcUrl, status:'new' });
    let clubId=null;
    try {
      try { const rec=await this.helpers.httpRequest({ method:'POST', url:PB_URL+'/api/collections/clubs/records', headers:pbH, body:full, json:true }); created++; dc++; clubId=rec.id; }
      catch(e){ const ex=await findClub(dedup); if(ex){ const patch=Object.assign({},base); if(website){patch.website_url=website;patch.website_source='official_list';} if(detail) patch.detail_url=detail; if(!ex.source_url) patch.source_url=srcUrl; await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+ex.id, headers:pbH, body:patch, json:true }); updated++; du++; clubId=ex.id; } else throw e; }
    } catch(e){ failed++; if(errors.length<10) errors.push({ key:dedup, message:(e&&e.message)||String(e) }); continue; }
    let savedC=0;
    const cts = Array.isArray(c&&c.contacts)?c.contacts:[];
    for (const ct of cts){
      const email=String((ct&&ct.email)||'').trim().toLowerCase(); if(!email||!isEmail(email)) continue;
      const nm=String((ct&&ct.name)||'').trim(), pos=String((ct&&ct.position)||'').trim(), ph=String((ct&&ct.phone)||'').trim();
      try { await this.helpers.httpRequest({ method:'POST', url:PB_URL+'/api/collections/contacts/records', headers:pbH, body:{ club:clubId, email, name:nm, position:pos, phone:ph, source_url:srcUrl, verification_status:'unverified', source_type:'directory' }, json:true }); contactsCreated++; savedC++; }
      catch(e){ try{ const ex=await findContact(email); if(ex){ const p={}; if(!ex.club)p.club=clubId; if(nm&&!ex.name)p.name=nm; if(pos&&!ex.position)p.position=pos; if(ph&&!ex.phone)p.phone=ph; if(!ex.source_url)p.source_url=srcUrl; if(Object.keys(p).length) await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/contacts/records/'+ex.id, headers:pbH, body:p, json:true }); } }catch(_){} }
    }
    if (savedC>0 && clubId){ try{ await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+clubId, headers:pbH, body:{ status:'contacts_found' }, json:true }); }catch(_){} }
  }
  perDir.push({ url:srcUrl, clubs:dc+du, created:dc, updated:du });
}

let status;
if (created+updated>0 && failed===0) status='scraped';
else if (failed>0) status='error';
else if (scrapeFails>0 && created+updated===0) status='error';
else status='needs_review';
await setFed({ status, last_scraped:now, club_count: detectedCount });
return [{ json: { ok: failed===0 && status==='scraped', federation:fivb, directories:perDir, total:totalClubs, created, updated, failed, scrapeFails, contactsCreated, errors } }];

const isClean = (t) => { const ls=String(t||'').split('\n').map(l=>l.trim()).filter(Boolean); if (ls.length<3) return true; const piped=ls.filter(l=>l.includes('|')).length; const listy=ls.filter(l=>/^([-*\u2022]|\d+[.)])\s+/.test(l)||/^\d+\s+\S/.test(l)).length; const prose=ls.filter(l=>l.length>220 && !l.includes('|')).length; return (Math.max(piped,listy)/ls.length >= 0.3) || (prose/ls.length < 0.1); };
const picks = $('pick pdfs').all().map(i=>i.json);
if (picks.length===1 && picks[0].__skip) return [{ json:{ __skip:true, note:picks[0].note, dirIndex:null, clean:true } }];
const sc = $('Extract PDF text').all().map(i=>i.json);
const CHUNK = 25000;
const out=[];
for (let d=0; d<picks.length; d++){
  const url = picks[d].url||''; const region = picks[d].region||'';
  const md = (sc[d] && typeof sc[d].text==='string' ? sc[d].text : '') || '';
  if (!md){ out.push({ json:{ dirIndex:d, dirUrl:url, region, chunk:'', chunkIndex:0, nChunks:0, scrapeFailed:true, clean:true } }); continue; }
  let header=''; const hm = md.match(/(?:^|\n)(\|[^\n]*\|)\n(\|[\s:|-]+\|)/); if(hm) header = hm[1]+'\n'+hm[2]+'\n';
  const lines = md.split('\n'); const chunks=[]; let cur='';
  for (const ln of lines){ if (cur.length + ln.length + 1 > CHUNK && cur){ chunks.push(cur); cur=''; } cur += ln + '\n'; }
  if (cur.trim()) chunks.push(cur); if(!chunks.length) chunks.push(md);
  const clean = isClean(md);
  chunks.forEach((c,ci)=>{ const chunk = (ci>0 && header && c.indexOf(header.trim())<0) ? header+c : c; out.push({ json:{ dirIndex:d, dirUrl:url, region, chunk, chunkIndex:ci, nChunks:chunks.length, clean } }); });
}
return out;
